module RefModule(
    input clk,
    input reset,
    input [4:0] in,
    output reg [4:0] out);
  wire _tap_clk = clk & {1{1'b1}};


    reg [4:0] in_last;

    always @(posedge clk) begin
        if (reset)
            out <= 5'b0;
        else begin
            in_last <= in;
            out <= out | (~in_last & in);
        end
    end
endmodule
